"""
context | Numbers 30-31 | Vows, holy war against Midian
Run: python3 scripts/zc-context-numbers-30-31.py

Ch 30: Laws governing vows — women's vows and the authority of father/husband to annul;
       ANE vow practice, silence as consent, widow/divorced woman's autonomy
Ch 31: Holy war (herem) against Midian — the Balaam execution, Phinehas as war-priest,
       purification rites for warriors, war-spoil distribution, the 12,000 casualty-free army
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


NUMBERS_CONTEXT = {
    "30": {
        "1": "<p>Moses speaks to the heads of the Israelite tribes about vow-law. The address 'to the heads of the tribes' (<i>roshei hammatot</i>) signals this as communal law applicable to clan leaders who will adjudicate disputes. Vows (<i>nedarim</i>) and pledges (<i>shebuˁot</i>) were legally binding in all ANE cultures — Akkadian, Ugaritic, and Egyptian texts attest to the seriousness with which they were treated. Breaking a vow was both a legal and a religious offense; Num 30 addresses how vows made by women under male authority structures are to be handled.</p>",
        "2": "<p>'When a man makes a vow to YHWH or swears an oath to bind himself with a pledge, he shall not break his word.' The principle is absolute for men: a vow is unbreakable once made. Deut 23:21–23 reinforces this: 'when you make a vow to the LORD your God, you shall not delay fulfilling it.' Qohelet 5:4–5 applies the same principle: it is better not to vow than to vow and not pay. The verb <i>yeḥallel</i> (profane, break) is a strong term — breaking a vow is not just a civil failure but a desecration.</p>",
        "3": "<p>The case of a young woman still living in her father's household: if she makes a vow, its validity is contingent on her father's response. The woman's legal capacity to make binding vows exists but is subject to paternal authority within the household structure. This reflects the ANE patriarchal household as the basic legal unit: a daughter is under her father's legal jurisdiction until transferred to a husband's household.</p>",
        "4": "<p>If the father hears and says nothing (<i>heḥerish lah</i> — literally 'keeps silent to/for her'), the vow stands and she must fulfill it. Silence is defined as consent in this legal framework — a principle that appears across ANE legal texts. The Hammurabi Code and Neo-Babylonian legal documents similarly treat the silent party's inaction as ratification of a legal state.</p>",
        "5": "<p>If the father nullifies (<i>heniˀ</i>) the vow on the day he hears of it, the vow is void and YHWH will forgive her. The father has a one-day window — the day of hearing — to exercise his authority. After that window, silence has become consent. The forgiveness formula ('YHWH will forgive her') implies the vow was already binding before annulment and that there is some guilt attached to voiding it that requires divine pardon.</p>",
        "6": "<p>The case of a woman who makes a vow while under her father's authority and then marries. The pre-marriage vow carries over into the marriage relationship. The husband now has the same authority as the father — he may nullify on the day he hears of it. ANE marriage contracts consistently transferred legal jurisdiction from father to husband; this verse reflects that transfer explicitly in the religious-vow domain.</p>",
        "7": "<p>The same silence-as-consent principle applies to the husband: if he hears and is silent on the day, the vow stands. The legal consistency between paternal and marital authority is deliberate — the law's structure is that a woman's vow operates within the authority of whoever heads her household, not that her vow-making capacity is inherently different from a man's.</p>",
        "8": "<p>If the husband nullifies the vow after hearing it on the day, he effectively bears the woman's iniquity. The husband's nullification transfers the legal consequences to him — a form of legal substitution. This is a specific case of vicarious responsibility that has no exact ANE parallel: the nullifying party absorbs the obligation rather than simply canceling it.</p>",
        "9": "<p>The widow or divorced woman — any vow she makes shall stand. These women have no male household head over them; they have the full legal capacity of a man with respect to vows. The legal autonomy of the widow and divorced woman is explicitly protected: they cannot appeal to a father or husband to void an obligation, but neither can anyone void their vows for them. This is the one case in the chapter where a woman's vow has the same absolute force as a man's.</p>",
        "10": "<p>A wife in her husband's household who makes a vow or an oath with a binding pledge is subject to the same day-of-hearing rule. The consistency of the household authority principle across all domestic states (unmarried daughter, newly married, long-married) reflects a systematic legal framework, not ad-hoc rulings.</p>",
        "11": "<p>If the husband has consistently been silent day after day about her vows and pledges, they stand — his ongoing silence ratifies them cumulatively. This extends the single-day rule into a cumulative pattern: a husband cannot ignore vows for weeks and then retrospectively nullify them when convenient. The fairness of the law's design protects the woman against arbitrary late revocation.</p>",
        "12": "<p>But if the husband nullifies them on the day he hears of them, then whatever she said about vows or pledges shall not stand. The phrase 'her husband has nullified them, and YHWH will forgive her' is the standard formula — the burden transfers to the husband. The pattern of the law is: the one who acts (nullifies) bears the consequence; the one who is acted upon (has their vow voided) is exculpated.</p>",
        "13": "<p>The general principle: every vow and every binding oath to deny herself (<i>leˁannot nefesh</i> — to afflict the soul, typically referring to fasting) her husband may either ratify or void. The 'affliction of the soul' is the specific category of self-denial vows — fasting being the primary example (compare Lev 23:27, Yom Kippur; Ps 35:13). These are specifically named because they affect the household — a fasting wife affects food preparation, shared meals, and household rhythms.</p>",
        "14": "<p>If the husband says nothing from day to day, he ratifies all her vows and pledges by his silence, because he said nothing to her on the day he heard. The law's logic is equitable from a property-law perspective: vows often involved dedicating household resources; the husband's right to override protects household assets, but the narrow window (one day) prevents abuse.</p>",
        "15": "<p>If the husband tries to nullify after the one-day window has passed, he bears her iniquity himself. This is the law's enforcement clause: an attempted late nullification does not succeed in removing the woman's obligation but does transfer moral-legal guilt to the husband. The law protects the woman from being left in a position of having incurred guilt through no fault of her own.</p>",
        "16": "<p>Moses delivers these statutes to Israel as YHWH commanded. The chapter functions as a self-contained legal unit on vow-authority within the household. Its position after the festival calendar (ch 28–29) and before the Midian holy war (ch 31) may reflect an editorial logic: the vow chapter closes the liturgical-calendar section before the narrative resumes.</p>",
    },
    "31": {
        "1": "<p>YHWH commands Moses to execute vengeance (<i>niqmat bˁnei yisraˀel</i>) on Midian before Moses dies. This is directly connected to the Baal Peor incident (Num 25) where Midianite women were the agents of Israel's seduction into apostasy at Phinehas's instigation (25:16–18). The 'vengeance' language is covenantal: Midian's action was an attack on YHWH's covenant people through deliberate seduction to apostasy, not merely a military provocation.</p>",
        "2": "<p>'After that you will be gathered to your people' — the Midian war is Moses' final military commission. The phrase 'gathered to your people' (<i>tˀasef ˀel-ˁameicha</i>) is the standard OT death formula for covenant members (also of Abraham, Gen 25:8; Isaac, Gen 35:29; Aaron, Num 20:24). It connotes not mere biological death but entry into the community of the ancestors. Moses' death is framed as honorable completion, not termination.</p>",
        "3": "<p>Moses summons warriors 'from among you' — a levy rather than a standing army. The phrase 'armed for war' (<i>ḥalutzim latzavaˀ</i>) uses the root <i>ḥltz</i> (equip, draw out for war), the same root as in Josh 1:14 (armed men crossing the Jordan). The levy principle reflects the tribal militia structure of early Israel — no professional military class, but the community's able-bodied men serve as needed.</p>",
        "4": "<p>A thousand from each tribe — 12,000 total. The representative levy of 1,000 per tribe (the same unit as in the census structure) produces a balanced force rather than a mass mobilization. The number 12,000 is almost certainly stylized to reflect tribal completeness and covenant symmetry rather than a precise historical muster. The same representational principle governs the 12,000 sealed in Rev 7:4–8.</p>",
        "5": "<p>The 12,000 warriors are levied from the thousands of Israel. The phrase 'thousands of Israel' (<i>ˀalfei yisraˀel</i>) uses the same ambiguous term as the census numbers — <i>ˀelef</i> may mean a literal thousand or a military unit/clan. The narrative presents a precisely organized levy, emphasizing divine order over the chaos of battle.</p>",
        "6": "<p>Phinehas son of Eleazar goes with the army, bearing the holy vessels and the trumpets (<i>ḥatzotzerot hattruˁah</i>). Phinehas's presence makes this a priestly war, not merely a military one. The holy vessels and the trumpets for sounding are the tabernacle instruments used in Num 10 to signal the camp's movements — their presence at a battle indicates YHWH is present and directing. This is a formal <i>milḥemet mitzvah</i> (commanded war) under priestly supervision.</p>",
        "7": "<p>Israel makes war against Midian as YHWH commanded and kills all the males. The phrase 'as YHWH commanded Moses' frames the entire operation as divinely authorized — the morality of the action is derived from divine command, not Israelite aggression. The five Midianite kings named (Evi, Rekem, Zur, Hur, and Reba) are also listed in Josh 13:21 as vassals of Sihon king of Amorites, situating Midian within the broader Transjordanian political landscape.</p>",
        "8": "<p>Balaam son of Beor is killed among the other slain. The Balaam execution is theologically significant: Balaam could not curse Israel (Num 22–24), but his counsel led to Israel's seduction at Peor (Num 31:16; compare Rev 2:14 — 'the teaching of Balaam, who taught Balak to put a stumbling block before the sons of Israel'). Balaam's death with the sword (<i>beḥarev</i>) is his accounting for the Peor counsel. His end is the counter-narrative to his prophetic career: unable to destroy Israel with words, he tried with deeds, and perished.</p>",
        "9": "<p>The Israelites take the Midianite women, children, livestock, flocks, and goods as spoil. This is the standard procedure for herem (devoted war) with important distinctions: in full herem (like Jericho, Josh 6), nothing is kept; in partial herem, enemy males are killed but women, children, and property can be kept. Num 31 occupies an intermediate position — the initial treatment of captives is later revised (vv.17–18).</p>",
        "10": "<p>All the Midianite cities and camps are burned with fire. The destruction of habitations alongside the capture of people and property follows the full destruction protocol for enemy centers. The burning of cities renders them uninhabitable and prevents reoccupation — this is consistent with archaeological evidence of Late Bronze Age destruction layers at sites across the Levant.</p>",
        "11": "<p>The army brings the captives, the livestock, and all the spoil to Moses, Aaron, and the congregation at the plains of Moab. The return to the camp for accounting and distribution follows the formal protocol of a commanded war — the military operation is subordinate to priestly and civil oversight. The plains of Moab (ˁarvot moˀav) is the final wilderness encampment before crossing the Jordan.</p>",
        "12": "<p>The spoil includes captives (both people and animals) alongside goods. The distinction between living captives (<i>shˀviyah</i>) and goods (<i>malqoaḥ</i>) anticipates the later instructions about what to do with the women captives (vv.14–18). The camp is at the plains of Moab — the same location where Moses delivers Deuteronomy.</p>",
        "13": "<p>Moses, Eleazar the priest, and all the congregation's leaders go out to meet the returning army. The formal reception outside the camp is a ritual of transition: warriors returning from battle carry impurity from contact with the dead and must be processed before re-entering the sanctuary camp. Eleazar's presence signals that the impurity-management will be the primary concern.</p>",
        "14": "<p>Moses is angry with the military commanders for preserving the women alive. The anger is theologically motivated: the Midianite women were the specific agents of Baal Peor seduction (31:16 — 'they caused the people of Israel to act treacherously against YHWH in the incident of Peor'). Preserving the women reverses the logic of punitive war: the very agents of the apostasy have been brought into camp.</p>",
        "15": "<p>'Have you let all the women live?' — Moses' rhetorical question exposes the contradiction. The Midianite women's role in the Peor incident was not incidental; Num 25:1–2 describes how 'the women invited the people to the sacrifices of their gods,' and 25:18 explicitly attributes the plague to 'the affair of Cozbi, the daughter of the chief of Midian.' These are identified women; their preservation in the camp is a direct threat to covenant integrity.</p>",
        "16": "<p>Moses names the specific agent of the apostasy: 'these women, on Balaam's advice, caused the people of Israel to act treacherously against YHWH in the incident of Peor.' This is the explicit connection between Balaam's counsel and the Peor apostasy that the narrative of Num 25 only implied. The book of Revelation applies this pattern to the church at Pergamum (Rev 2:14), naming 'the teaching of Balaam' as a paradigm of seduction-to-idolatry through female agency within the community.</p>",
        "17": "<p>Moses orders the execution of all male children and all women who have slept with a man. The command is harsh by any standard; it raises the moral question that dominates modern engagement with this text. Within the narrative's own logic: (1) Midianite males represent a future military threat; (2) non-virgin women were agents of Baal Peor seduction. The category preserved — 'young girls who have not known a man' — are those untouched by the specific theological crime.</p>",
        "18": "<p>The young girls who are virgins are kept alive for themselves. These girls would be integrated into Israelite families as slaves, wives, or concubines — the same fate as female war captives in Deut 21:10–14. The moral logic of the ancient world: captives are the victor's property; preservation of life (even in servitude) is preferred to indiscriminate killing. Modern readers bring different moral frameworks; the ancient near eastern legal context is an essential point of reference for understanding what this legislation was doing, even while not minimizing its difficulty.</p>",
        "19": "<p>Purification instructions for the warriors: anyone who killed a person or touched a corpse must stay outside the camp for seven days. This is the same red heifer purification protocol of Num 19 — contact with a corpse (even in authorized war) creates ritual impurity. The seven-day purification timeline (days 3 and 7 with water of impurity) is required before re-entering the tabernacle camp. The warriors are not guilty of sin — killing in commanded war is not sinful — but ritual impurity must still be addressed.</p>",
        "20": "<p>Every garment, leather article, goat-hair item, or wooden article must also be purified. The impurity of death extends to objects as well as persons — a principle consistent with Lev 11:32 (objects contaminated by unclean animals must be purified). The practical effect is that all war spoil brought back is potentially contaminated and must undergo purification before use.</p>",
        "21": "<p>Eleazar the priest speaks the purification instruction to the warriors — Moses defers to the priest on ritual matters, which is consistent with the Aaronic priesthood's authority over purification law. The instruction Eleazar gives is described as 'the statute of the law that YHWH commanded Moses,' connecting it to the red heifer law of ch 19.</p>",
        "22": "<p>The metals — gold, silver, bronze, iron, tin, lead — must be purified differently from organic materials: they go through fire (v.23) because they can withstand it. This creates a practical distinction in purification methodology: fire-proof materials are purified by fire; other materials are purified by the water of impurity. The six-metal list is consistent with the metals used in tabernacle construction (Exod 25–31), suggesting that metalwork captured from Midian may ultimately be dedicated to the sanctuary.</p>",
        "23": "<p>'Whatever can withstand fire, you shall pass through fire, and it shall be clean.' The purification-by-fire principle for metals is practical and theological: fire both cleanses contamination and refines the metal. The combination of fire purification and water of impurity purification ensures complete cleansing. Zechariah 13:9 and Malachi 3:2–3 use this smelting-for-purification metaphor theologically.</p>",
        "24": "<p>After the fire and water purification, the warriors wash their garments on the seventh day and are then clean. The sequence: seven days outside camp → purification on day 3 and day 7 with water of impurity → washing garments on day 7 → clean. This is the full red heifer protocol applied to war-camp reintegration. The precision of the instructions reflects the priestly concern for maintaining the holiness gradient of the camp.</p>",
        "25": "<p>YHWH instructs Moses and Eleazar to take a count of the spoil. The precise accounting of war plunder is standard in ancient military administration. Egyptian inscriptions (including the Annals of Thutmose III at Karnak) list captured spoil with meticulous detail: number of persons, livestock, and goods. The Midian accounting follows this same administrative precision.</p>",
        "26": "<p>The division of spoil is between the warriors who fought and the whole congregation — a specific principle of communal participation in the benefits of war even for non-combatants. The division principle here differs from David's later formulation (1 Sam 30:24: 'the share of him who stays by the supplies shall be the same as the share of him who goes into battle'), but establishes the same fundamental principle of communal participation.</p>",
        "27": "<p>Half the spoil to the warriors, half to the congregation. The 50/50 split between combatants and non-combatants is unusual — most ANE war-spoil conventions gave a larger share to fighters. The equal division reflects the theological principle that the victory belonged to YHWH acting for all Israel, not to the military elite.</p>",
        "28": "<p>From the warriors' half, a levy is taken for YHWH: one in five hundred of persons, cattle, donkeys, sheep, and goats. The levy for YHWH is YHWH's tithe from the army's share — not from the congregation's share. The tithe principle (a portion dedicated to YHWH) extends from agricultural produce to war spoil, establishing the principle that YHWH's share is always first from any acquisition.</p>",
        "29": "<p>The levy from the warriors' half goes to Eleazar the priest as a contribution (<i>terumah</i>) to YHWH. The <i>terumah</i> is the specific Hebrew term for a contribution elevated/dedicated to God — the same word used for the heave offering in the sanctuary worship (Exod 25:2; Lev 22:12). The application of sanctuary terminology to war spoil integrates military victory into the worship framework.</p>",
        "30": "<p>From the congregation's half, a levy of one in fifty is given to the Levites who keep charge of YHWH's tabernacle. The congregation's levy (1 in 50) is larger proportionally than the warriors' levy (1 in 500), which seems counterintuitive. The different rates may reflect: (1) the congregation's greater portion being proportionally taxed to support the Levites; (2) the different purposes — warriors' levy goes to Eleazar for the sanctuary; congregation's levy goes to the Levites for tabernacle service.</p>",
        "31": "<p>Moses and Eleazar obey YHWH's command exactly. The compliance formula ('as YHWH commanded Moses') appears repeatedly throughout Numbers to underscore the importance of precise obedience in the holy war context. Any deviation from commanded procedure in sacred war risked contamination of the community (compare Achan's sin in Josh 7).</p>",
        "32": "<p>The total spoil remaining after the warriors kept their plunder: 675,000 sheep, 72,000 cattle, 61,000 donkeys, and 32,000 virgin girls. The numbers are large — more characteristic of royal campaign records than a small-unit action. The Assyrian annals routinely record captures of hundreds of thousands of livestock; whether the Numbers figures are literal or stylized is a perennial debate among biblical scholars. The presence of a counting and accounting system, however, is historically realistic.</p>",
        "33": "<p>The livestock totals are listed in sequence: the 675,000 sheep heads the list as the most numerous category. The proportion of sheep to cattle (approximately 9:1) is consistent with the pastoral economy of the Midianite region (semi-nomadic pastoralists in the Hejaz/Sinai kept more small livestock than large). The numbers' precision is part of the text's accounting genre — comparison with exact halves and fractions in subsequent verses shows systematic math.</p>",
        "34": "<p>The 61,000 donkeys are specifically enumerated separately from cattle. Donkeys were the primary pack and transport animal of the ancient Near East (horses were rare and prestigious; camels not yet domesticated at this scale for most of the Bronze Age). A herd of 61,000 donkeys represents enormous transport capacity — consistent with a semi-nomadic people who relied on donkey caravans for their economy.</p>",
        "35": "<p>The 32,000 virgin girls constitute the human captive total. As the only people group not subject to Moses' execution order (vv.17–18), they represent the surviving non-combatant females under a certain age. The enumeration places them within the war-spoil accounting rather than distinguishing them as a fundamentally different category from livestock — a feature of the text that reflects ANE war conventions but is deeply uncomfortable to modern readers.</p>",
        "36": "<p>The warriors' half of the sheep: 337,500 (half of 675,000). The halving and levying arithmetic is precisely consistent, showing the text's intent to demonstrate careful administration. The warriors' share of sheep (337,500) is taxed at 1-in-500, yielding the YHWH levy of 675 sheep (v.37).</p>",
        "37": "<p>YHWH's levy from the warriors' sheep: 675. The math: 337,500 ÷ 500 = 675. The precision of the arithmetic is characteristic of priestly administrative texts — the same precision appears in the Levitical head-count/redemption arithmetic of Num 3 (22,000 Levites vs. 22,273 firstborn, with 5-shekel redemption for the 273 surplus). The book of Numbers is unusually attentive to exact figures.</p>",
        "38": "<p>The warriors' half of cattle: 36,000; YHWH's levy: 72. Math: 36,000 ÷ 500 = 72. The levy amounts (675 sheep, 72 cattle, 61 donkeys, 32 persons) go to Eleazar the priest, not to the general priesthood. Eleazar receives the elevated holy-of-holies equivalent of the war-spoil tithe — consistent with his role as Phinehas's father and the presiding priest of the campaign.</p>",
        "39": "<p>The warriors' half of donkeys: 30,500; YHWH's levy: 61. Math: 30,500 ÷ 500 = 61. The three livestock categories — sheep, cattle, donkeys — are consistently taxed at the 1-in-500 rate. Their combined tax (675 + 72 + 61 = 808 animals) goes to the tabernacle sanctuary through Eleazar.</p>",
        "40": "<p>The warriors' half of persons: 16,000; YHWH's levy: 32 persons given to Eleazar. The application of the same 1-in-500 levy to persons as to animals is a feature of ANE war-accounting in which human captives were enumerated alongside livestock as property. The 32 persons given to Eleazar presumably serve at the sanctuary — the same category as the <i>netunim</i> (given ones) of Ezra 8:20.</p>",
        "41": "<p>Moses gives the levy (675 sheep, 72 cattle, 61 donkeys, 32 persons) to Eleazar as YHWH commanded. The compliance formula again: 'as YHWH commanded Moses.' The delegation from Moses to Eleazar is consistent with the post-Aaron succession: Eleazar has assumed his father's role as senior priest, and Moses defers to him in priestly matters.</p>",
        "42": "<p>The congregation's half of sheep: 337,500. The mirror of the warriors' half — the congregation receives the same absolute number, confirming the 50/50 split. The congregation's tax (1-in-50) on 337,500 sheep = 6,750 sheep for the Levites (v.47).</p>",
        "43": "<p>The congregation's half of cattle: 36,000. The parallel accounting continues. The congregation's half of each category exactly mirrors the warriors' half, confirming the mathematical precision of the accounting and the equity of the division.</p>",
        "44": "<p>The congregation's half of donkeys: 30,500. The Midianite pastoral wealth — represented by the large herds of sheep, cattle, and donkeys — now passes into Israelite ownership and is formally accounted and tithed. The tabernacle service benefits from both the Eleazar levy (small, from warriors) and the Levite levy (larger, from congregation).</p>",
        "45": "<p>The congregation's half of persons: 16,000. The full captive count (32,000 virgin girls divided equally) is distributed between warriors and congregation. The congregation's share (16,000) provides labor and household service for Israelite families — the integration of foreign captive women into Israelite households is regulated later in Deut 21:10–14.</p>",
        "46": "<p>The congregation's 16,000 persons (for completeness of the accounting sequence before the Levite levy is calculated).</p>",
        "47": "<p>Moses takes one in fifty from the congregation's share and gives it to the Levites who keep charge of the tabernacle. The Levite levy: one in fifty from the congregation's 337,500 sheep = 6,750 sheep; from 36,000 cattle = 720; from 30,500 donkeys = 610; from 16,000 persons = 320. The Levites receive approximately 10x more than Eleazar's share — consistent with the Levites' role as the general tabernacle workforce rather than the specific priestly office.</p>",
        "48": "<p>The military commanders (commanders of thousands and commanders of hundreds) come before Moses and report: 'Your servants have counted the soldiers under our command, and not one is missing.' The astonishing claim — no Israelite casualties in the Midian campaign — is theologically significant. The casualty-free holy war is unprecedented and unrepeated in the OT; it marks this war as uniquely YHWH's war, fought with such divine precision that no covenant soldier died.</p>",
        "49": "<p>The commanders present themselves in the context of the count — their accountability before Moses mirrors the census theology throughout Numbers: everyone is counted before YHWH. The casualty count of zero is a theological statement about divine protection in a sanctioned holy war, not a claim about military tactics.</p>",
        "50": "<p>As a result, the commanders bring a freewill contribution (<i>qorban YHWH</i>) from their individual war booty: gold articles, armlets, bracelets, signet rings, earrings, and pendants. These are personal adornments — jewelry items plundered from Midianite individuals, quite different from the official spoil accounting above. The voluntary offering comes from personal plunder not included in the official distribution.</p>",
        "51": "<p>Moses and Eleazar receive the gold from them — all worked articles. The enumeration of jewelry types (armlets/wristbands, bracelets, signet rings, earrings, pendants) reflects the actual repertoire of ANE personal jewelry attested in Egyptian and Canaanite hoards. The Midianite material culture included fine metalwork consistent with the trading networks of the incense route.</p>",
        "52": "<p>The total gold from the commanders: 16,750 shekels. A shekel weighs approximately 11.4 grams; 16,750 shekels ≈ 191 kg of gold. This is a substantial but not impossible quantity of gold jewelry for a large Midianite confederation — comparable to treasure-hoards described in Egyptian conquest records. The gold will be brought to the tabernacle as a memorial before YHWH.</p>",
        "53": "<p>Each soldier had taken his own plunder — implicitly not included in the official spoil accounting. The commanders' voluntary contribution comes out of this personal plunder, not the officially allocated shares. The distinction between official spoil (divided per command) and personal plunder (each soldier's individual acquisition) is consistent with ANE military practice and appears in the Hammurabi Code's treatment of war booty.</p>",
        "54": "<p>Moses and Eleazar bring the gold into the tent of meeting as a memorial (<i>zikkaron</i>) for the Israelites before YHWH. The <i>zikkaron</i> (memorial/reminder) is the purpose of the offering: it will stand before YHWH as a perpetual record of the campaign's divine success and the commanders' gratitude. The same word is used for the memorial stones at the Jordan crossing (Josh 4:7) and the Passover (Exod 12:14). The chapter closes with the spoil entering the sanctuary — the holy war is complete and its fruits consecrated.</p>",
    },
}


def main():
    data = load_comm("mkt-context", "numbers")
    merge_comm(data, NUMBERS_CONTEXT)
    save_comm("mkt-context", "numbers", data)


if __name__ == "__main__":
    main()
